"use client";
// Mirrors React-template Tab01.jsx–Tab07.jsx

import { useState, type ReactNode } from "react";
import IconWithText, { IWTItem } from "./IconWithText";

export interface TabItem {
  tabTitle: string;
  tabIcon?: ReactNode;
  subtitle?: string;
  title?: string;
  img?: string;
  content?: string;
  buttonTitle?: string;
  buttonLink?: string;
  featurebox?: IWTItem[];
  activities?: { icon?: ReactNode; text: string; meta?: string }[];
  schedule?: { time: string; title: string; speaker?: string }[];
  accordion?: { title: string; content: string }[];
}

interface Props {
  theme?: "tab-style-01" | "tab-style-02" | "tab-style-03" | "tab-style-04" | "tab-style-05" | "tab-style-06" | "tab-style-07";
  data: TabItem[];
}

export default function Tab({ theme = "tab-style-01", data }: Props) {
  const [active, setActive] = useState(0);

  if (theme === "tab-style-02") return <TabStyle02 data={data} active={active} setActive={setActive} />;
  if (theme === "tab-style-03") return <TabStyle03 data={data} active={active} setActive={setActive} />;
  if (theme === "tab-style-04") return <TabStyle04 data={data} active={active} setActive={setActive} />;
  if (theme === "tab-style-05") return <TabStyle05 data={data} active={active} setActive={setActive} />;
  if (theme === "tab-style-06") return <TabStyle06 data={data} active={active} setActive={setActive} />;
  if (theme === "tab-style-07") return <TabStyle07 data={data} active={active} setActive={setActive} />;
  return <TabStyle01 data={data} active={active} setActive={setActive} />;
}

/* ── Tab-style-01: image left + text right ── */
function TabStyle01({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const item = data[active];
  return (
    <div className="tab-style-01">
      <div className="tab-nav">
        {data.map((t, i) => (
          <button key={i} onClick={() => setActive(i)} className={`tab-btn ${active === i ? "active" : ""}`}>
            {t.tabIcon && <span className="mr-2">{t.tabIcon}</span>}
            {t.tabTitle}
          </button>
        ))}
      </div>

      <div className="tab-pane active" style={{ gridTemplateColumns: "1fr 1fr", gap: "3rem", alignItems: "center", paddingTop: "3rem" }}>
        <div>
          {item.img && <img src={item.img} alt={item.title || ""} className="w-full object-cover rounded" style={{ maxHeight: 400 }} />}
        </div>
        <div>
          {item.subtitle && <p className="section-label text-[--primary] mb-4">{item.subtitle}</p>}
          {item.title   && <h2 className="heading-5 text-[--dark] mb-6">{item.title}</h2>}
          {item.content && <p className="text-[--text] leading-relaxed mb-8">{item.content}</p>}
          {item.buttonTitle && (
            <a href={item.buttonLink || "#"} className="btn-link-fancy">{item.buttonTitle}</a>
          )}
        </div>
      </div>
    </div>
  );
}

/* ── Tab-style-07: consulting tabs with featurebox ── */
function TabStyle07({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const item = data[active];
  return (
    <div className="tab-style-07">
      <div className="tab-nav mb-12">
        {data.map((t, i) => (
          <button key={i} onClick={() => setActive(i)} className={`tab-btn ${active === i ? "active" : ""}`}>
            {t.tabTitle}
          </button>
        ))}
      </div>

      <div className="container-xl">
        <div className="tab-pane active" style={{ gridTemplateColumns: "1fr 1fr", gap: "4rem", alignItems: "center" }}>
          {/* Left: image + subtitle badge */}
          <div className="relative">
            {item.img && <img src={item.img} alt={item.title || ""} className="w-full object-cover rounded" style={{ height: 460 }} />}
            {item.subtitle && (
              <div className="absolute top-10 -left-3.75 text-white font-light text-xl px-10 py-8 max-w-70 leading-snug md:hidden"
                style={{ background: "linear-gradient(135deg, var(--primary), var(--primary-dark))" }}>
                {item.subtitle}
              </div>
            )}
          </div>
          {/* Right: title + features + link */}
          <div>
            {item.title && <h2 className="heading-5 text-[--dark] mb-10">{item.title}</h2>}
            {item.featurebox && (
              <IconWithText theme="icon-with-text-01" data={item.featurebox} grid="grid-cols-1" />
            )}
            {item.buttonTitle && (
              <a href={item.buttonLink || "#"} className="btn-link-fancy mt-10 inline-flex">{item.buttonTitle}</a>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── Tab-style-02: icon tabs + image side-panel ── */
function TabStyle02({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const item = data[active];
  return (
    <div className="tab-style-02">
      <div className="tab-nav">
        {data.map((t, i) => (
          <button key={i} onClick={() => setActive(i)} className={`tab-btn ${active === i ? "active" : ""}`}>
            {t.tabIcon && <span className="tb-icon">{t.tabIcon}</span>}
            {t.tabTitle}
          </button>
        ))}
      </div>
      <div className="tab-panel active">
        {item.img && <img src={item.img} alt={item.title || ""} />}
        <div className="tp-content">
          {item.title && <h5>{item.title}</h5>}
          {item.content && <p>{item.content}</p>}
        </div>
      </div>
    </div>
  );
}

/* ── Tab-style-03: pill tabs + activity list ── */
function TabStyle03({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const item = data[active];
  return (
    <div className="tab-style-03">
      <div className="tab-nav">
        {data.map((t, i) => (
          <button key={i} onClick={() => setActive(i)} className={`tab-btn ${active === i ? "active" : ""}`}>{t.tabTitle}</button>
        ))}
      </div>
      <div className="tab-panel active">
        <ul className="activity-list">
          {(item.activities || []).map((a, i) => (
            <li key={i}>
              <div className="al-icon">{a.icon || "★"}</div>
              <div>
                <div>{a.text}</div>
                {a.meta && <div className="al-meta">{a.meta}</div>}
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

/* ── Tab-style-04: toggle switch (e.g. monthly/annual pricing) ── */
function TabStyle04({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const toggle = () => setActive(active === 0 ? 1 : 0);
  return (
    <div className="tab-style-04">
      <div className="tab-toggle">
        <span className="tg-label">{data[0]?.tabTitle}</span>
        <div className={`tg-switch ${active === 1 ? "toggled" : ""}`} onClick={toggle} />
        <span className="tg-label">{data[1]?.tabTitle}</span>
      </div>
      {data.map((item, i) => (
        <div key={i} className={`tab-panel ${active === i ? "active" : ""}`}>
          {item.content && <p>{item.content}</p>}
        </div>
      ))}
    </div>
  );
}

/* ── Tab-style-05: pill tabs + accordion body ── */
function TabStyle05({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const [openAcc, setOpenAcc] = useState(0);
  const item = data[active];
  return (
    <div className="tab-style-05">
      <div className="tab-nav">
        {data.map((t, i) => (
          <button key={i} onClick={() => { setActive(i); setOpenAcc(0); }} className={`tab-btn ${active === i ? "active" : ""}`}>{t.tabTitle}</button>
        ))}
      </div>
      <div className="tab-panel active">
        {(item.accordion || []).map((a, i) => (
          <div key={i} className={`acc-item ${openAcc === i ? "open" : ""}`}>
            <div className="acc-header" onClick={() => setOpenAcc(openAcc === i ? -1 : i)}>
              <span>{a.title}</span>
              <span>{openAcc === i ? "−" : "+"}</span>
            </div>
            <div className="acc-body">{a.content}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ── Tab-style-06: pill tabs + schedule/timetable ── */
function TabStyle06({ data, active, setActive }: { data: TabItem[]; active: number; setActive: (i: number) => void }) {
  const item = data[active];
  return (
    <div className="tab-style-06">
      <div className="tab-nav">
        {data.map((t, i) => (
          <button key={i} onClick={() => setActive(i)} className={`tab-btn ${active === i ? "active" : ""}`}>{t.tabTitle}</button>
        ))}
      </div>
      <div className="tab-panel active">
        {(item.schedule || []).map((s, i) => (
          <div key={i} className="schedule-row">
            <div className="sr-time">{s.time}</div>
            <div className="sr-title">{s.title}</div>
            {s.speaker && <div className="sr-speaker">{s.speaker}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}
